async def _on_watchdog_alert(component: str, message: str):
    """Handle camera/worker stall: restart capture, notify user."""
    logger.warning('Watchdog alert [%s]: %s', component, message)
    if component == 'camera':
        # Attempt to restart the persistent video stream
        try:
            if userdata.visual_processor._persistent_stream:
                try:
                    await userdata.visual_processor._persistent_stream.aclose()
                except Exception:
                    pass
                userdata.visual_processor._persistent_stream = None
                userdata.visual_processor._cached_video_track = None
                logger.info('Camera stream reset by watchdog')
        except Exception as exc:
            logger.error('Camera restart failed: %s', exc)
        # Speak warning to user
        try:
            if hasattr(agent_session, 'say'):
                await agent_session.say(
                    'Camera appears disconnected. Trying to reconnect. Please proceed with caution.'
                )
        except Exception:
            pass

userdata._watchdog.on_alert(_on_watchdog_alert)

