"""Download ML models for spatial perception."""
import os, urllib.request, hashlib

MODELS = [
    {
        'name': 'yolov8n.onnx',
        'url': 'https://github.com/ultralytics/assets/releases/download/v8.1.0/yolov8n.onnx',
        'sha256': None,  # Fill after first download
        'env_var': 'YOLO_MODEL_PATH',
    },
    {
        'name': 'midas_v21_small_256.onnx',
        'url': 'https://github.com/isl-org/MiDaS/releases/download/v3_1/midas_v21_small_256.onnx',
        'sha256': None,
        'env_var': 'MIDAS_MODEL_PATH',
    },
]

MODEL_DIR = os.path.join(os.path.dirname(__file__), '..', 'models')
os.makedirs(MODEL_DIR, exist_ok=True)

for m in MODELS:
    dest = os.path.join(MODEL_DIR, m['name'])
    if os.path.exists(dest):
        print(f'  [skip] {m["name"]} already exists')
        continue
    print(f'  Downloading {m["name"]}...')
    urllib.request.urlretrieve(m['url'], dest)
    print(f'  Saved to {dest}')

print('\nDone. Set these environment variables:')
for m in MODELS:
    print(f'  {m["env_var"]}=models/{m["name"]}')

